// Angel investing math for a FAANG Staff+ engineer
const angelPortfolio = {
  annualInvestment: 100000,     // $100K/year from RSU savings
  yearsActive: 10,
  totalDeployed: 1000000,      // $1M total over 10 years
  numInvestments: 30,          // 30 startups funded
  expectedOutcomes: {
    fail: { probability: 0.65, return: 0 },        // 65% fail → $0
    survive: { probability: 0.20, return: 1.5 },   // 20% return 1.5x
    exitSmall: { probability: 0.10, return: 5 },   // 10% return 5x
    exitLarge: { probability: 0.05, return: 30 },  // 5% return 30x
  },
  expectedReturn: 0.3,  // 30% annualized if thesis is right
  medianReturn: 0.05     // 5% annualized (most angels lose money)
};
// Key insight: angel investing is attractive for optionality, not expected value

// Post-FAANG financial independence calculator
const faangEngineer = {
  currentAge: 38,
  annualExpenses: 120000,       // $120K/year lifestyle
  currentInvestments: 2500000,  // $2.5M saved (stocks, 401K, etc.)
  safeWithdrawalRate: 0.035,    // 3.5% conservative SWR

  // Independence calculations
  leanFI: 1000000,              // $1M = $35K/year (lean lifestyle)
  coastFI: 1800000,             // $1.8M = no more savings needed
  standardFI: 3000000,          // $3M = $105K/year (current lifestyle)
  fatFI: 5000000,               // $5M = $175K/year (upgraded lifestyle)
  fuMoney: 3500000,             // $3.5M = FU money territory

  // Your status: CoastFI ✅ (2.5M > 1.8M)
  // Your status: StandardFI ❌ (2.5M < 3M)
  // Recommendation: Can take lower-paying role but still need runway to StandardFI
  nextStep: "Fractional CTO at $30K/month + angel investing"
};
console.log(`Coast FI reached at $$ {faangEngineer.coastFI}`);
console.log(`Standard FI target: $$ {faangEngineer.standardFI}`);
